        /* <flatten type="Javascript"> */
var f = this, v = f._language == 'v', g = f.getItem('d96')._controlBehavior;
var s = f.getItem('status').value, p = f.getItem('xs_name').value, q = f.getItem('xs').value, d = g._getColumnOrder('qc_yn'), e = g._getColumnOrder('xstatus_name%l'), k = g._getColumnOrder('sl_kt'), l = g._getColumnOrder('so_luong'), l1 = g._getColumnOrder('stt_rec_dh');
var t = f.getItemValue('ma_kh');
var errorMessage = (v ? 'Thông tin mã nhà cung cấp của phiếu nhập mua phải giống với đơn hàng.' : 'Purchase Receipt should have same supplier information as Purchase Order.');

for(var row = 1; row <= g._rowCount; row ++) {
  if (s == 0) g._setItemValue(row, e, '');
  else {
    if (g._getItemValue(row, k) >= g._getItemValue(row, l)) g._setItemValue(row, e, p);
    else {
      if (!g._getItemValue(row, d)) g._setItemValue(row, e, p);
        else g._setItemValue(row, e, q);
    }
  }

  var v1 = (g._getItemValue(row, l1) != '');
  if (v1 != ''){
    var u = g._getItem(row, 1)._customerIdentity;
    if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
    if (t != u) {
      $func.hideWait(f.get_id());
      $message.show(errorMessage, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', f.get_id()));
      f._checked = false;
      break;
    }
  }
}
f.setItemValue('ngay_ct', f.getItemValue('ngay_lct'));
/* </flatten> */
