script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {
  &ScriptActiveVoucher;&VoucherLogHandleStatus;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$Voucher$DefaultValue(f);

      &ListCreate;
      &PostCreate;

}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&VoucherLogHandleStatus;set$Voucher$DefaultValue(f);}
function close$Voucher$(f) {
  &ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d96')._controlBehavior;
  switch (action)	{
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;

      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d96')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
   	v.set_currencyFields('t_tien_nt:t_tien');
    v.addGridFields(g, 'gia_nt,tien_nt:gia,tien');
    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_tien', 'tien']]);
    v.set_referenceFields(null);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d96', 'ma_vt']&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
	    break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    case 'ChangeStatus':
		  f.setItemControlBehavior('xs_name', result[0].Value, null, true);
	  break;
    case 'Customer':
      f.setItemControlBehavior('ong_ba', result[0].Value, null, true);
      f.live(f.getItem('ong_ba'));
      break;
      &ListResponseTicket;
    default:
      break;
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged([['d96', 'ma_vt']&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
function on$ChangeStatus(o) {o.parentForm.request('ChangeStatus', 'ChangeStatus', ['status']);}
function set$Voucher$DefaultValue(f) {
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  if (f._action == 'New') f.setItemValue('xs_name', f._ext1);
  f.setItemValue('xs', f._ext2);
}
/* </flatten> */
